const items = $input.all();
const d = items[0].json;

// Validacao do telefone
const telefone = (d.admin_telefone || '').toString().trim();
const telefoneValido = /^55\d{2}9\d{8}$/.test(telefone);

if (!telefoneValido) {
  return [{ json: { telefone: '', mensagem: '', erro: 'Telefone invalido ou ausente: ' + (d.admin_telefone || '(vazio)') + ' -> ' + telefone, enviar: false } }];
}

const total = Number(d.total_pedidos) || 0;
const entregues = Number(d.entregues) || 0;
const cancelados = Number(d.cancelados) || 0;
const preparando = Number(d.preparando) || 0;
const emAndamento = Number(d.em_andamento) || 0;
const faturamento = Number(d.faturamento) || 0;
const fatStr = faturamento.toFixed(2).replace('.', ',');

const hoje = new Date();
const dia = String(hoje.getDate()).padStart(2, '0');
const mes = String(hoje.getMonth() + 1).padStart(2, '0');
const ano = hoje.getFullYear();
const dataStr = dia + '/' + mes + '/' + ano;

const msg = '\ud83d\udcca *RESUMO DO DIA*\n'
  + dataStr + '\n'
  + '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n\n'
  + '\ud83d\udce6 Pedidos: *' + total + '*\n'
  + '\u2705 Entregues: *' + entregues + '*\n'
  + (preparando > 0 ? '\ud83d\udc68\u200d\ud83c\udf73 Preparando: *' + preparando + '*\n' : '')
  + (emAndamento > 0 ? '\u23f3 Em andamento: *' + emAndamento + '*\n' : '')
  + '\u274c Cancelados: *' + cancelados + '*\n\n'
  + '\ud83d\udcb0 *Faturamento: R$ ' + fatStr + '*\n\n'
  + '\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\u2501\n'
  + '_Resumo automatico - Inventro_';

return [{ json: { telefone: telefone, mensagem: msg, enviar: true } }];
